import java.io.*;
import java.nio.file.*;
import java.nio.charset.StandardCharsets;

public class CountKeywordLines {
  public static void main(String[] args) throws IOException {
    Path path = Paths.get("input.txt");
    String keyword = "error";
    int count = 0;
    try (BufferedReader br = Files.newBufferedReader(path, StandardCharsets.UTF_8)) {
      for (String line; (line = br.readLine()) != null; ) {
        if (line.contains(keyword)) count++;
      }
    }
    System.out.println("Lines containing '" + keyword + "': " + count);
  }
}

import java.io.*;
import java.nio.file.*;
import java.nio.charset.StandardCharsets;

public class NumberedCopy {
  public static void main(String[] args) throws IOException {
    Path inPath = Paths.get("in.txt");
    Path outPath = Paths.get("out.txt");
    try (BufferedReader br = Files.newBufferedReader(inPath, StandardCharsets.UTF_8);
         PrintWriter pw = new PrintWriter(Files.newBufferedWriter(outPath, StandardCharsets.UTF_8))) {
      int lineNo = 1;
      for (String line; (line = br.readLine()) != null; ) {
        pw.println(lineNo + ": " + line);
        lineNo++;
      }
    }
  }
}

import java.io.*;
import java.nio.file.*;
import java.nio.charset.StandardCharsets;

public class SumTSVColumn {
  public static void main(String[] args) throws IOException {
    Path path = Paths.get("data.tsv");
    int columnIndex = 2;
    double sum = 0.0;
    try (BufferedReader br = Files.newBufferedReader(path, StandardCharsets.UTF_8)) {
      String line;
      while ((line = br.readLine()) != null) {
        String[] fields = line.split("\t", -1);
        if (fields.length > columnIndex && !fields[columnIndex].isEmpty()) {
          sum += Double.parseDouble(fields[columnIndex]);
        }
      }
    }
    System.out.println("Sum: " + sum);
  }
}
